:host {
  display: block;
  height: 100%;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

.nx-label-editor {
  --nx-accent: #5469FF;
  --nx-bg: #ffffff;
  --nx-text-primary: #0f172a;
  --nx-text-secondary: #64748b;
  --nx-border: #e2e8f0;
  --nx-radius: 12px;
  --nx-pad: 16px;

  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: var(--nx-pad);
  background: var(--nx-bg);
  border-radius: var(--nx-radius);
  box-shadow: 0 1px 2px rgba(15,23,42,.04), 0 1px 3px rgba(15,23,42,.03);
  height: 100%;
  box-sizing: border-box;
}

.nx-header {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--nx-text-secondary);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.nx-header .nx-icon {
  font-size: 15px;
  color: var(--nx-accent);
}

.nx-current {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}

.nx-value {
  font-size: 20px;
  font-weight: 600;
  color: var(--nx-text-primary);
  letter-spacing: -0.01em;
  flex: 1 1 auto;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  min-width: 0;
}

.nx-edit-row {
  display: flex;
  align-items: center;
  gap: 6px;
}

.nx-input {
  flex: 1 1 auto;
  min-width: 0;
  padding: 8px 12px;
  border: 1.5px solid var(--nx-border);
  border-radius: 8px;
  font-family: inherit;
  font-size: 15px;
  font-weight: 500;
  color: var(--nx-text-primary);
  background: #f8fafc;
  outline: none;
  transition: border-color 0.15s;
}

.nx-input:focus {
  border-color: var(--nx-accent);
  background: #fff;
}

.nx-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  border: none;
  border-radius: 8px;
  width: 34px;
  height: 34px;
  cursor: pointer;
  transition: background 0.15s, opacity 0.15s;
  flex-shrink: 0;
}

.nx-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.nx-btn .material-icons { font-size: 18px; }

.nx-btn-edit {
  background: color-mix(in srgb, var(--nx-accent) 12%, transparent);
  color: var(--nx-accent);
}
.nx-btn-edit:hover { background: color-mix(in srgb, var(--nx-accent) 20%, transparent); }

.nx-btn-save {
  background: var(--nx-accent);
  color: #fff;
}
.nx-btn-save:hover:not(:disabled) { background: #4356d4; }

.nx-btn-cancel {
  background: #f1f5f9;
  color: var(--nx-text-secondary);
}
.nx-btn-cancel:hover:not(:disabled) { background: #e2e8f0; }

.nx-feedback {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 12px;
  font-weight: 500;
  padding: 6px 10px;
  border-radius: 6px;
}

.nx-feedback .material-icons { font-size: 15px; }

.nx-feedback-error {
  background: #fef2f2;
  color: #dc2626;
}

.nx-feedback-ok {
  background: #f0fdf4;
  color: #16a34a;
}

@media (prefers-color-scheme: dark) {
  .nx-label-editor {
    --nx-bg: #0f172a;
    --nx-text-primary: #f8fafc;
    --nx-text-secondary: #94a3b8;
    --nx-border: #334155;
    box-shadow: 0 1px 2px rgba(0,0,0,.3);
  }
  .nx-input {
    background: #1e293b;
    color: #f8fafc;
  }
  .nx-input:focus { background: #0f172a; }
  .nx-btn-cancel { background: #1e293b; }
}

descriptor.controllerScript:
self.onInit = function() {
  var ctx = self.ctx;

  // Inyectar deviceService
  var $injector = ctx.$scope.$injector;
  self._deviceService = $injector.get(ctx.servicesMap.get('deviceService'));

  // Estado inicial del scope
  ctx.$scope.currentLabel = '—';
  ctx.$scope.editValue    = '';
  ctx.$scope.isEditing    = false;
  ctx.$scope.isSaving     = false;
  ctx.$scope.errorMsg     = '';
  ctx.$scope.successMsg   = '';

  // El entityId del device viene del datasource
  self._entityId = null;

  // Acciones del scope
  ctx.$scope.startEdit = function() {
    ctx.$scope.editValue  = ctx.$scope.currentLabel;
    ctx.$scope.isEditing  = true;
    ctx.$scope.errorMsg   = '';
    ctx.$scope.successMsg = '';
    ctx.detectChanges();
    // Focus al input en el próximo tick
    setTimeout(function() {
      var input = ctx.$container[0].querySelector('.nx-input');
      if (input) input.focus();
    }, 50);
  };

  ctx.$scope.cancelEdit = function() {
    ctx.$scope.isEditing = false;
    ctx.$scope.errorMsg  = '';
    ctx.detectChanges();
  };

  ctx.$scope.saveLabel = function() {
    var newLabel = (ctx.$scope.editValue || '').trim();
    if (!newLabel) {
      ctx.$scope.errorMsg = 'El nombre no puede estar vacío.';
      ctx.detectChanges();
      return;
    }
    if (newLabel === ctx.$scope.currentLabel) {
      ctx.$scope.isEditing = false;
      ctx.detectChanges();
      return;
    }
    if (!self._entityId) {
      ctx.$scope.errorMsg = 'No se encontró el device ID.';
      ctx.detectChanges();
      return;
    }

    ctx.$scope.isSaving = true;
    ctx.$scope.errorMsg = '';
    ctx.detectChanges();

    // 1. Traer el objeto device completo
    self._deviceService.getDevice(self._entityId).subscribe(
      function(device) {
        // 2. Modificar sólo el label
        device.label = newLabel;

        // 3. Guardar
        self._deviceService.saveDevice(device).subscribe(
          function(saved) {
            ctx.$scope.currentLabel = saved.label || newLabel;
            ctx.$scope.isEditing    = false;
            ctx.$scope.isSaving     = false;
            ctx.$scope.successMsg   = 'Nombre actualizado correctamente.';
            ctx.detectChanges();
            // Limpiar mensaje de éxito después de 3 seg
            setTimeout(function() {
              ctx.$scope.successMsg = '';
              ctx.detectChanges();
            }, 3000);
          },
          function(err) {
            ctx.$scope.isSaving = false;
            ctx.$scope.errorMsg = 'Error al guardar. ¿Tenés permisos de escritura sobre el device?';
            console.error('[LabelEditor] saveDevice error:', err);
            ctx.detectChanges();
          }
        );
      },
      function(err) {
        ctx.$scope.isSaving = false;
        ctx.$scope.errorMsg = 'Error al obtener el device.';
        console.error('[LabelEditor] getDevice error:', err);
        ctx.detectChanges();
      }
    );
  };
};

self.onDataUpdated = function() {
  var ctx = self.ctx;
  var data = ctx.data;
  if (!data || !data.length) return;

  var ds = data[0].datasource;
  if (ds && ds.entity && ds.entity.id) {
    self._entityId = ds.entity.id.id;  // UUID string
  }

  // El label del device llega como propiedad del datasource, no como telemetría
  // Lo leemos de entityName o buscamos en los datos
  if (ds && ds.entityLabel != null && ds.entityLabel !== '') {
    ctx.$scope.currentLabel = ds.entityLabel;
  } else if (ds && ds.entityName) {
    // fallback al name si no hay label
    ctx.$scope.currentLabel = ds.entityName;
  }

  ctx.detectChanges();
};

self.onDestroy = function() {
  // nada que limpiar
};

